//! Rendering helpers shared across every per-target emitter.
//!
//! These routines are purely presentation-layer: string literal escaping,
//! case conversion, param-type projection per language, and the shared
//! `@generated` header. Nothing here mutates the spec.

use std::fmt::Write as _;

use super::spec::{ParamSpec, ParamType};

/// Returns the `@generated DO NOT EDIT` banner prepended to each rendered source file.
pub(super) fn generated_header() -> &'static str {
    "// @generated DO NOT EDIT — regenerated by build.rs from sdk_surface.toml\n\n"
}

/// Returns an escaped, quoted Rust string literal for the given value.
pub(super) fn rust_string_literal(value: &str) -> String {
    format!("{value:?}")
}

/// Returns a Rust array literal of escaped, quoted string literals for the given values.
pub(super) fn rust_string_array_literal(values: &[String]) -> String {
    let mut out = String::from("[");
    for (index, value) in values.iter().enumerate() {
        if index > 0 {
            out.push_str(", ");
        }
        out.push_str(&rust_string_literal(value));
    }
    out.push(']');
    out
}

/// Appends `doc`, one `///` line per input line, indented by `indent`, to `out`.
pub(super) fn push_rust_doc_comment(out: &mut String, indent: &str, doc: &str) {
    for line in doc.lines() {
        if line.is_empty() {
            // Avoid trailing whitespace on blank doc-comment lines —
            // `git diff --check` treats `/// ` (slashes followed by a
            // single trailing space) as a whitespace error.
            writeln!(out, "{indent}///").unwrap();
        } else {
            writeln!(out, "{indent}/// {line}").unwrap();
        }
    }
}

/// Appends `doc` as a C++ Doxygen comment (`/** */` block or one-line form), indented by `indent`, to `out`.
pub(super) fn push_cpp_doc_comment(out: &mut String, indent: &str, doc: &str) {
    if doc.contains('\n') {
        writeln!(out, "{indent}/**").unwrap();
        for line in doc.lines() {
            if line.is_empty() {
                // Same trailing-whitespace guard as the Rust emitter.
                writeln!(out, "{indent} *").unwrap();
            } else {
                writeln!(out, "{indent} * {line}").unwrap();
            }
        }
        writeln!(out, "{indent} */").unwrap();
    } else {
        writeln!(out, "{indent}/** {doc} */").unwrap();
    }
}

/// Returns the param's MCP-facing argument name, falling back to its canonical name.
pub(super) fn mcp_param_name(param: &ParamSpec) -> &str {
    param.mcp_name.as_deref().unwrap_or(&param.name)
}

/// Returns the param's MCP-facing description, falling back to its doc text.
pub(super) fn mcp_param_description(param: &ParamSpec) -> &str {
    param.mcp_description.as_deref().unwrap_or(&param.doc)
}

/// Maps a spec param type to its JSON Schema type name used in MCP tool definitions.
pub(super) fn mcp_json_type(param_type: ParamType) -> &'static str {
    match param_type {
        ParamType::String => "string",
        ParamType::F64 => "number",
        ParamType::I32 | ParamType::I64 | ParamType::U64 => "integer",
        ParamType::CredentialsRef | ParamType::ConfigRef => {
            panic!("credentials/config refs are not valid for MCP emitters")
        }
    }
}
